const lenis = new Lenis({
  autoRaf: true,
  lerp: 0.1,
  autoResize: true,
});

const header = document.querySelector('header');
const headerMenuButton = header?.querySelector('.header__burger');
const headerMenu = header?.querySelector('.header__menu');

function setHeaderMenu(isOpen) {
    if (!header || !headerMenuButton || !headerMenu) return;

    header.classList.toggle('menu-open', isOpen);
    header.classList.remove('back');
    headerMenuButton.setAttribute('aria-expanded', String(isOpen));
    headerMenuButton.setAttribute('aria-label', isOpen ? 'Закрыть меню' : 'Открыть меню');
    headerMenu.setAttribute('aria-hidden', String(!isOpen));
    document.documentElement.classList.toggle('menu-open', isOpen);

    if (isOpen) {
        lenis.stop();
    } else {
        lenis.start();
        refreshLenis();
    }
}

headerMenuButton?.addEventListener('click', () => {
    setHeaderMenu(!header.classList.contains('menu-open'));
});

headerMenu?.querySelectorAll('a').forEach((link) => {
    link.addEventListener('click', () => setHeaderMenu(false));
});

document.addEventListener('keydown', (event) => {
    if (event.key === 'Escape' && header?.classList.contains('menu-open')) {
        setHeaderMenu(false);
        headerMenuButton.focus();
    }
});

const desktopHeaderQuery = window.matchMedia('(min-width: 1201px)');

desktopHeaderQuery.addEventListener('change', (event) => {
    if (event.matches) setHeaderMenu(false);
});

const catalogFilterQuery = window.matchMedia('(max-width: 900px)');

document.querySelectorAll('[data-catalog-filter]').forEach((filter) => {
    const scope = filter.closest('.routes');
    const openButton = scope?.querySelector('[data-catalog-filter-open]');
    const closeButton = filter.querySelector('[data-catalog-filter-close]');

    const setCatalogFilter = (isOpen) => {
        filter.classList.toggle('is-open', isOpen);
        filter.setAttribute('aria-hidden', String(!isOpen));
        openButton?.setAttribute('aria-expanded', String(isOpen));
        document.documentElement.classList.toggle('filter-open', isOpen);

        if (isOpen) {
            lenis.stop();
            closeButton?.focus();
        } else {
            lenis.start();
            refreshLenis();
        }
    };

    openButton?.addEventListener('click', () => setCatalogFilter(true));
    closeButton?.addEventListener('click', () => setCatalogFilter(false));
    filter.addEventListener('click', (event) => {
        if (event.target === filter) setCatalogFilter(false);
    });
    document.addEventListener('keydown', (event) => {
        if (event.key === 'Escape' && filter.classList.contains('is-open')) {
            setCatalogFilter(false);
            openButton?.focus();
        }
    });
    catalogFilterQuery.addEventListener('change', (event) => {
        if (!event.matches) setCatalogFilter(false);
    });
});

lenis.on('scroll', (e) => {
    if (!header || header.classList.contains('menu-open')) return;
    if (lenis.targetScroll >= 150) {
        if (lenis.direction == 1) {
            header.classList.add('back')
        }else{
            header.classList.remove('back')
        }
    }
});

function refreshLenis() {
    lenis.resize();
    requestAnimationFrame(() => lenis.resize());
}

function refreshLenisAfterTransition(element) {
    const onTransitionEnd = (event) => {
        if (event.target !== element || event.propertyName !== 'max-height') return;
        window.clearTimeout(fallback);
        lenis.resize();
        element.removeEventListener('transitionend', onTransitionEnd);
    };

    const fallback = window.setTimeout(() => {
        lenis.resize();
        element.removeEventListener('transitionend', onTransitionEnd);
    }, 550);

    element.addEventListener('transitionend', onTransitionEnd);
    refreshLenis();
}


const faqItems = document.querySelectorAll('.faq__item');

faqItems.forEach((item) => {
    const button = item.querySelector('.faq__item-head');
    const wrapper = item.querySelector('.faq__item-wrapper');

    button.addEventListener('click', () => {
        const shouldOpen = !item.classList.contains('current');

        faqItems.forEach((faqItem) => {
            faqItem.classList.remove('current');
            faqItem.querySelector('.faq__item-head').setAttribute('aria-expanded', 'false');
            faqItem.querySelector('.faq__item-wrapper').style.maxHeight = '0px';
        });

        if (shouldOpen) {
            item.classList.add('current');
            button.setAttribute('aria-expanded', 'true');
            wrapper.style.maxHeight = `${wrapper.scrollHeight}px`;
        }

        refreshLenisAfterTransition(wrapper);
    });
});

let descriptionItems = document.querySelectorAll('.description')

descriptionItems.forEach((item) => {
    let button = item.querySelector('.description__button button')
    let wrapperItem = item.querySelector('.description__content')
    const staticHeight = window.getComputedStyle(wrapperItem).maxHeight;
    button.addEventListener('click', function () {
        if (wrapperItem.classList.contains('show')) {
            wrapperItem.style.maxHeight = `${staticHeight}`;
            wrapperItem.classList.remove('show')
        } else {
            const wrapperHeight = wrapperItem.scrollHeight;
            wrapperItem.classList.add('show')
            wrapperItem.style.maxHeight = `${wrapperHeight}px`;
        }
        refreshLenisAfterTransition(wrapperItem);
    })
})

function getFieldInputs(field) {
    return [...field.querySelectorAll('input, textarea, select')];
}

function getPhoneDigits(value) {
    return value.replace(/\D/g, '');
}

function formatPhone(value) {
    let digits = getPhoneDigits(value);

    if (digits.startsWith('8')) {
        digits = `7${digits.slice(1)}`;
    }

    if (digits.length > 0 && !digits.startsWith('7')) {
        digits = `7${digits}`;
    }

    digits = digits.slice(0, 11);

    const parts = [
        digits.slice(1, 4),
        digits.slice(4, 7),
        digits.slice(7, 9),
        digits.slice(9, 11),
    ];

    let result = '+7';

    if (parts[0]) result += ` (${parts[0]}`;
    if (parts[0].length === 3) result += ')';
    if (parts[1]) result += ` ${parts[1]}`;
    if (parts[2]) result += `-${parts[2]}`;
    if (parts[3]) result += `-${parts[3]}`;

    return result;
}

function isFilledInput(input) {
    if (!input) return false;

    if (input.matches('[data-phone-mask]')) {
        return getPhoneDigits(input.value).length === 11;
    }

    return input.value.trim().length > 0;
}

function isFilledField(field) {
    const inputs = getFieldInputs(field);
    const radioInputs = inputs.filter((input) => input.type === 'radio');

    if (radioInputs.length > 0) {
        return radioInputs.some((input) => input.checked);
    }

    return isFilledInput(inputs[0]);
}

function setFieldError(field, hasError) {
    if (!field) return;

    field.classList.toggle('is-error', hasError);
    getFieldInputs(field).forEach((input) => {
        input.setAttribute('aria-invalid', String(hasError));
    });
}

function clearFieldError(field) {
    setFieldError(field, false);
}

function initPhoneMasks(scope = document) {
    scope.querySelectorAll('[data-phone-mask]').forEach((input) => {
        input.addEventListener('input', () => {
            input.value = formatPhone(input.value);

            if (isFilledInput(input)) {
                clearFieldError(input.closest('[data-required-field]'));
            }
        });

        input.addEventListener('focus', () => {
            if (!input.value.trim()) {
                input.value = '+7';
            }
        });

        input.addEventListener('blur', () => {
            if (getPhoneDigits(input.value).length <= 1) {
                input.value = '';
            }
        });
    });
}

function initRequestSelects(scope = document) {
    const selects = scope.querySelectorAll('[data-request-select]');

    const setOpen = (select, isOpen) => {
        select.classList.toggle('is-open', isOpen);
        const input = select.querySelector('[role="combobox"]');

        input?.setAttribute('aria-expanded', String(isOpen));

        if (!isOpen) {
            input?.removeAttribute('aria-activedescendant');
            select.querySelectorAll('[data-select-option]').forEach((option) => {
                option.classList.remove('is-active');
            });
        }
    };

    selects.forEach((select) => {
        const input = select.querySelector('input');
        const options = [...select.querySelectorAll('[data-select-option]')];
        let activeOptionIndex = -1;

        const setActiveOption = (index) => {
            activeOptionIndex = (index + options.length) % options.length;

            options.forEach((option, optionIndex) => {
                option.classList.toggle('is-active', optionIndex === activeOptionIndex);
            });

            input.setAttribute('aria-activedescendant', options[activeOptionIndex].id);
        };

        const chooseOption = (option) => {
            input.value = option.textContent.trim();
            options.forEach((item) => item.setAttribute('aria-selected', String(item === option)));
            input.dispatchEvent(new Event('input', { bubbles: true }));
            input.dispatchEvent(new Event('change', { bubbles: true }));
            setOpen(select, false);
            clearFieldError(select.closest('[data-required-field]'));
        };

        select.addEventListener('click', (event) => {
            const option = event.target.closest('[data-select-option]');

            if (option) {
                chooseOption(option);
                return;
            }

            const shouldOpen = !select.classList.contains('is-open');

            setOpen(select, shouldOpen);

            if (shouldOpen) {
                setActiveOption(Math.max(activeOptionIndex, 0));
            }
        });

        input.addEventListener('keydown', (event) => {
            if (event.key === 'Escape') {
                setOpen(select, false);
                return;
            }

            if (event.key === 'ArrowDown' || event.key === 'ArrowUp') {
                event.preventDefault();
                setOpen(select, true);
                const nextIndex = activeOptionIndex < 0
                    ? (event.key === 'ArrowDown' ? 0 : options.length - 1)
                    : activeOptionIndex + (event.key === 'ArrowDown' ? 1 : -1);

                setActiveOption(nextIndex);
                return;
            }

            if (event.key === 'Enter' || event.key === ' ') {
                event.preventDefault();

                if (select.classList.contains('is-open') && activeOptionIndex >= 0) {
                    chooseOption(options[activeOptionIndex]);
                    return;
                }

                setOpen(select, true);
                setActiveOption(Math.max(activeOptionIndex, 0));
            }
        });

        options.forEach((option, index) => {
            option.id = `${input.id}-option-${index + 1}`;
            option.setAttribute('role', 'option');
            option.setAttribute('aria-selected', 'false');
            option.setAttribute('tabindex', '-1');
        });
    });

    document.addEventListener('click', (event) => {
        selects.forEach((select) => {
            if (!select.contains(event.target)) {
                setOpen(select, false);
            }
        });
    });
}

function initRequestForms() {
    document.querySelectorAll('.request__form').forEach((form) => {
        const requiredFields = form.querySelectorAll('[data-required-field]');
        const policy = form.querySelector('.request__action-policy');
        const policyInput = policy?.querySelector('input[type="checkbox"]');

        requiredFields.forEach((field) => {
            const inputs = getFieldInputs(field);

            inputs.forEach((input) => {
                input.setAttribute('aria-required', 'true');
                input.setAttribute('aria-invalid', 'false');

                input.addEventListener('input', () => {
                    if (isFilledField(field)) {
                        clearFieldError(field);
                    }
                });

                input.addEventListener('change', () => {
                    if (isFilledField(field)) {
                        clearFieldError(field);
                    }
                });
            });
        });

        policyInput?.addEventListener('change', () => {
            const hasPolicyError = !policyInput.checked;

            policy.classList.toggle('is-error', hasPolicyError);
            policyInput.setAttribute('aria-invalid', String(hasPolicyError));
        });

        form.addEventListener('submit', (event) => {
            let isValid = true;

            requiredFields.forEach((field) => {
                const hasError = !isFilledField(field);

                setFieldError(field, hasError);
                isValid = isValid && !hasError;
            });

            if (policyInput) {
                const hasPolicyError = !policyInput.checked;

                policy.classList.toggle('is-error', hasPolicyError);
                policyInput.setAttribute('aria-invalid', String(hasPolicyError));
                isValid = isValid && !hasPolicyError;
            }

            if (!isValid) {
                event.preventDefault();
                form.querySelector('.is-error input')?.focus();
            }
        });
    });
}

initPhoneMasks();
initRequestSelects();
initRequestForms();

const audioBarHeights = [18, 26, 14, 34, 22, 30, 16, 38, 24, 32, 18, 28];

function formatAudioTime(seconds) {
    const safeSeconds = Math.max(0, Math.floor(seconds));
    const minutes = Math.floor(safeSeconds / 60);
    const restSeconds = safeSeconds % 60;

    return `${minutes}:${String(restSeconds).padStart(2, '0')}`;
}

function getAudioLimit(audio, fallbackDuration) {
    if (Number.isFinite(audio.duration) && audio.duration > 0) {
        return Math.min(audio.duration, fallbackDuration);
    }

    return fallbackDuration;
}

function setAudioPlayerState(player, isPlaying) {
    player.classList.toggle('is-playing', isPlaying);
    player.querySelector('button')?.setAttribute(
        'aria-label',
        isPlaying ? 'Остановить аудиопревью' : 'Воспроизвести аудиопревью',
    );
}

function updateAudioBars(bars, progress) {
    const activeBars = Math.ceil(bars.length * Math.max(0, Math.min(progress, 1)));

    bars.forEach((bar, index) => {
        bar.classList.toggle('is-active', index < activeBars);
    });
}

function updateAudioTime(time, seconds) {
    if (!time) return;

    time.textContent = formatAudioTime(seconds);
}

function resetAudioPlayer(player, audio, bars, time, fallbackDuration) {
    const limit = getAudioLimit(audio, fallbackDuration);

    audio.pause();
    audio.currentTime = 0;
    setAudioPlayerState(player, false);
    updateAudioBars(bars, 0);
    updateAudioTime(time, limit);
}

function initPersonAudioPlayers() {
    const players = document.querySelectorAll('.person__audio[data-audio-src]');

    players.forEach((player) => {
        const button = player.querySelector('button');
        const timeline = player.querySelector('.person__audio-timeline');
        const time = player.querySelector('[data-audio-time]');
        const audioSrc = player.dataset.audioSrc;
        const fallbackDuration = Number(player.dataset.audioDuration) || 30;
        const barsCount = Number(player.dataset.audioBars) || 36;

        if (!button || !timeline || !audioSrc) return;

        const audio = new Audio(audioSrc);
        audio.preload = 'metadata';
        const bars = [];

        timeline.innerHTML = '';

        for (let index = 0; index < barsCount; index += 1) {
            const bar = document.createElement('span');
            const height = audioBarHeights[index % audioBarHeights.length];

            bar.className = 'audio__bar';
            bar.style.setProperty('--bar-height', `${height}px`);
            timeline.append(bar);
            bars.push(bar);
        }

        updateAudioTime(time, fallbackDuration);

        audio.addEventListener('loadedmetadata', () => {
            updateAudioTime(time, getAudioLimit(audio, fallbackDuration));
        });

        audio.addEventListener('timeupdate', () => {
            const limit = getAudioLimit(audio, fallbackDuration);

            if (audio.currentTime >= limit) {
                resetAudioPlayer(player, audio, bars, time, fallbackDuration);
                return;
            }

            updateAudioBars(bars, audio.currentTime / limit);
            updateAudioTime(time, limit - audio.currentTime);
        });

        audio.addEventListener('ended', () => {
            resetAudioPlayer(player, audio, bars, time, fallbackDuration);
        });

        button.addEventListener('click', async () => {
            const isPlaying = player.classList.contains('is-playing');

            document.querySelectorAll('.person__audio.is-playing').forEach((activePlayer) => {
                activePlayer.dispatchEvent(new CustomEvent('audio:pause'));
            });

            if (isPlaying) {
                audio.pause();
                setAudioPlayerState(player, false);
                return;
            }

            try {
                await audio.play();
                setAudioPlayerState(player, true);
            } catch (error) {
                console.warn(error);
            }
        });

        timeline.addEventListener('click', (event) => {
            const bounds = timeline.getBoundingClientRect();
            const progress = (event.clientX - bounds.left) / bounds.width;
            const limit = getAudioLimit(audio, fallbackDuration);

            audio.currentTime = Math.max(0, Math.min(progress, 1)) * limit;
            updateAudioBars(bars, audio.currentTime / limit);
            updateAudioTime(time, limit - audio.currentTime);
        });

        player.addEventListener('audio:pause', () => {
            audio.pause();
            setAudioPlayerState(player, false);
        });
    });
}

initPersonAudioPlayers();

const yandexMapsScriptSrc = 'https://api-maps.yandex.ru/2.1/?lang=ru_RU';
let yandexMapsPromise;
const mapIconNodes = {
    coffee: Coffee,
    pin: MapPin,
};

function parseMapCoords(element) {
    const rawCoords = element.dataset.coords || element.dataset.choords || element.dataset.coordinates || '';
    const coords = rawCoords.split(',').map((item) => Number(item.trim()));

    if (coords.length !== 2 || coords.some((coord) => Number.isNaN(coord))) {
        return null;
    }

    return coords;
}

function escapeHtml(value = '') {
    return value.replace(/[&<>"']/g, (char) => ({
        '&': '&amp;',
        '<': '&lt;',
        '>': '&gt;',
        '"': '&quot;',
        "'": '&#039;',
    })[char]);
}

function createLucideSvg(iconNode, className = '') {
    const children = iconNode
        .map(([tag, attrs]) => {
            const attributes = Object.entries(attrs)
                .map(([key, value]) => `${key}="${escapeHtml(String(value))}"`)
                .join(' ');

            return `<${tag} ${attributes}></${tag}>`;
        })
        .join('');

    return `<svg class="${className}" xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">${children}</svg>`;
}

function createMapIconHtml(iconName) {
    const iconNode = mapIconNodes[iconName] || mapIconNodes.pin;
    const iconSvg = createLucideSvg(iconNode, 'map-marker__icon');

    return `
        <div style="
            width: 32px;
            height: 32px;
            border-radius: 50%;
            background: #1F63D4;
            color: #fff;
            display: flex;
            align-items: center;
            justify-content: center;
            box-shadow: 0 8px 24px rgba(17, 18, 20, 0.18);
            transform: translate(-50%, -50%);
        ">
            ${iconSvg}
        </div>
    `;
}

function loadYandexMaps(apiKey = '') {
    if (window.ymaps) {
        return Promise.resolve(window.ymaps);
    }

    if (yandexMapsPromise) {
        return yandexMapsPromise;
    }

    yandexMapsPromise = new Promise((resolve, reject) => {
        const script = document.createElement('script');
        const scriptUrl = new URL(yandexMapsScriptSrc);

        if (apiKey) {
            scriptUrl.searchParams.set('apikey', apiKey);
        }

        script.src = scriptUrl.toString();
        script.async = true;
        script.onload = () => {
            window.ymaps.ready(() => resolve(window.ymaps));
        };
        script.onerror = () => reject(new Error('Yandex Maps script failed to load'));

        document.head.append(script);
    });

    return yandexMapsPromise;
}

function createYandexMap(element, ymaps, coords) {
    const zoom = Number(element.dataset.zoom) || 16;
    const mapTitle = element.dataset.mapTitle || '';
    const mapAddress = element.dataset.mapAddress || '';
    const mapIcon = element.dataset.mapIcon || 'pin';
    const map = new ymaps.Map(element, {
        center: coords,
        zoom,
        controls: ['zoomControl'],
    });

    const placemark = new ymaps.Placemark(coords, {
        hintContent: escapeHtml(mapTitle),
        balloonContentHeader: escapeHtml(mapTitle),
        balloonContentBody: escapeHtml(mapAddress),
    }, {
        iconLayout: ymaps.templateLayoutFactory.createClass(createMapIconHtml(mapIcon)),
        iconShape: {
            type: 'Circle',
            coordinates: [0, 0],
            radius: 24,
        },
    });

    map.geoObjects.add(placemark);

    return map;
}

function initYandexMaps() {
    const mapElements = document.querySelectorAll('[data-yandex-map]');

    if (mapElements.length === 0) return;

    const apiKey = mapElements[0]?.dataset.apiKey || document.documentElement.dataset.yandexMapsApiKey || '';

    loadYandexMaps(apiKey)
        .then((ymaps) => {
            mapElements.forEach((element) => {
                if (element.dataset.mapInitialized === 'true') return;

                const coords = parseMapCoords(element);

                if (!coords) return;

                createYandexMap(element, ymaps, coords);
                element.dataset.mapInitialized = 'true';

                const openMapLink = element.closest('.place__article-map')?.querySelector('[data-open-map-link]');
                const openMapHref = openMapLink?.getAttribute('href')?.trim();

                if (openMapLink && (!openMapHref || openMapHref === '#')) {
                    openMapLink.href = `https://yandex.ru/maps/?ll=${coords[1]}%2C${coords[0]}&z=${element.dataset.zoom || 16}&pt=${coords[1]}%2C${coords[0]}%2Cpm2rdm`;
                    openMapLink.target = '_blank';
                    openMapLink.rel = 'noopener';
                }
            });
        })
        .catch((error) => {
            console.warn(error);
        });
}

initYandexMaps();


